// app/api/dashboard/route.ts
import { db } from '@/lib/db';
import { cache } from '@/lib/cache';
import { analytics } from '@/lib/analytics';

export async function GET(req: Request) {
  const session = await getSession(req);
  const userId = session.userId;

  // Fetch everything sequentially
  const user = await db.user.findUnique({ where: { id: userId } });
  const orders = await db.order.findMany({ where: { userId } });
  const recommendations = await getRecommendations(userId);
  const notifications = await db.notification.findMany({ where: { userId, read: false } });

  // Log analytics after response
  await analytics.track('dashboard_view', { userId });
  await analytics.track('active_user', { userId });

  // Cache result
  const cacheKey = `dashboard:${userId}`;
  const cached = cache.get(cacheKey);
  if (cached) return Response.json(cached);

  const result = { user, orders, recommendations, notifications };
  cache.set(cacheKey, result, { ttl: 60 });
  return Response.json(result);
}
