      <p>Count: {count}</p>
      <input onChange={handleSearch} />
      <button onClick={handleSort}>Sort</button>
      {sortedUsers.map((user, index) => (
        <UserCard key={index} user={user} style={DEFAULT_STYLE} isAdmin={isAdmin} />
      ))}
      {isAdmin && <AdminPanel users={users} />}
    </div>
  );
}

