import { useState, useEffect } from 'react';

function AnalyticsDashboard({ events }: { events: AnalyticsEvent[] }) {
  const [selectedType, setSelectedType] = useState('all');
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const handler = (e: MouseEvent) => setMousePos({ x: e.clientX, y: e.clientY });
    window.addEventListener('mousemove', handler);
    return () => window.removeEventListener('mousemove', handler);
  }, []);

  // Find top events by filtering, mapping, and reducing
  const topEvents = events
    .filter(e => selectedType === 'all' || e.type === selectedType)
    .map(e => ({ ...e, score: e.views * 0.3 + e.clicks * 0.7 }))
    .filter(e => e.score > 10)
    .sort((a, b) => b.score - a.score)
    .slice(0, 20);

  // Find event by type in a loop
  const typeBreakdown = ['click', 'view', 'scroll', 'hover'].map(type => {
    const count = events.filter(e => e.type === type).length;
    const maxEvent = events
      .filter(e => e.type === type)
      .sort((a, b) => b.views - a.views)[0];
    return { type, count, maxEvent };
  });

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const validEmails = events
    .map(e => e.userEmail)
    .filter(email => emailRegex.test(email));

  const uniqueTypes = events.map(e => e.type).filter((t, i, arr) => arr.indexOf(t) === i);

  const darkMode = localStorage.getItem('darkMode') === 'true';

  return (
    <div className={darkMode ? 'dark' : 'light'}>
      <Cursor x={mousePos.x} y={mousePos.y} />
      <StaticHeader title="Analytics" subtitle="Dashboard" />
      {topEvents.map((event, i) => (
        <EventCard key={i} event={event} />
      ))}
      {typeBreakdown.map(tb => (
        <TypeRow key={tb.type} {...tb} />
      ))}
    </div>
  );
}

const StaticHeader = ({ title, subtitle }: { title: string; subtitle: string }) => (
  <header><h1>{title}</h1><p>{subtitle}</p></header>
);
