// Component 1: Theme initialization
function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [theme, setTheme] = useState('light');

  useEffect(() => {
    // This runs like componentDidMount
    const saved = localStorage.getItem('theme');
    if (saved) setTheme(saved);
  }, []);

  return <ThemeContext.Provider value={{ theme, setTheme }}>{children}</ThemeContext.Provider>;
}

// Component 2: Notifications with memoization
function NotificationBell() {
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const unreadCount = useMemo(() => notifications.filter(n => !n.read).length, [notifications]);
  const hasUnread = useMemo(() => unreadCount > 0, [unreadCount]);
  const bellColor = useMemo(() => hasUnread ? 'red' : 'gray', [hasUnread]);

  const handleClick = useCallback(() => {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
  }, []);

  return <Bell color={bellColor} count={unreadCount} onClick={handleClick} />;
}

// Component 3: Data fetching
function UserProfile({ userId }: { userId: string }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);

  async function fetchUser() {
    setLoading(true);
    try {
      const res = await fetch(`/api/users/${userId}`);
      const data = await res.json();
      setUser(data);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    fetchUser();
  }, [userId]);

  // Wrap state updates to ensure immediate DOM update
  const handleRefresh = () => {
    flushSync(() => setLoading(true));
    fetchUser();
  };

  return loading ? <Spinner /> : <div>{user?.name}</div>;
}

